<?php
/**
 * SpinWheel Pro V2 — RBAC System Deployment Patch v2.1.0
 * ═══════════════════════════════════════════════════════
 * Deploys 22 files: includes/ and admin/ for full RBAC.
 *
 * 1. Upload this file to your web root (beside /admin/, /includes/)
 * 2. Visit the file URL in your browser
 * 3. Click "Deploy Now"
 * 4. Run the migration link shown on success
 * 5. DELETE this file AND migrate_rbac.php immediately after
 * ═══════════════════════════════════════════════════════
 */
set_time_limit(300);
define('PATCH_VER','2.1.0-rbac');
$ROOT   = __DIR__;
$OK     = [];
$ERRORS = [];
$RUN    = (isset($_POST['deploy']) && $_POST['deploy']==='yes');

if ($RUN) {
    $raw     = base64_decode('');
    $payload = json_decode($raw, true);
    if (!$payload) {
        $ERRORS[] = 'Payload decode failed - re-upload the file.';
    } else {
        foreach ($payload as $rel => $b64) {
            $full    = $ROOT.'/'.$rel;
            $dir     = dirname($full);
            $content = base64_decode($b64);
            if (!is_dir($dir) && !mkdir($dir,0755,true)) { $ERRORS[]="Cannot create: $dir"; continue; }
            if (file_put_contents($full,$content)!==false) { $OK[]=[$rel,strlen($content)]; }
            else { $ERRORS[]="Cannot write: $rel"; }
        }
    }
}

$scheme = (!empty($_SERVER['HTTPS'])&&$_SERVER['HTTPS']!=='off')?'https':'http';
$host   = $_SERVER['HTTP_HOST']??'localhost';
$doc    = rtrim(str_replace("\\","/",(string)realpath($_SERVER['DOCUMENT_ROOT']??'')),'/');
$app    = rtrim(str_replace("\\","/",(string)realpath(__DIR__)),'/');
$sub    = ($doc&&strlen($doc)&&str_starts_with($app,$doc))?substr($app,strlen($doc)):'';
$URL    = rtrim($scheme.'://'.$host.$sub,'/');
?>
