*{box-sizing:border-box;margin:0;padding:0}body{font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:var(--bg);color:var(--t1);padding:40px 20px}
.w{max-width:680px;margin:0 auto}h1{font-size:21px;margin-bottom:6px}
.sub{color:var(--t2);font-size:13px;margin-bottom:28px}
