h2{font-size:15px;font-weight:600;margin-bottom:12px}
.row{display:flex;align-items:flex-start;gap:10px;padding:7px 11px;border-radius:6px;margin-bottom:4px;font-size:12px;font-family:monospace}
.ok-r{background:rgba(34,197,94,.07);border:1px solid rgba(34,197,94,.2);color:#86efac}
.err-r{background:rgba(239,68,68,.07);border:1px solid rgba(239,68,68,.2);color:#fca5a5}
