.b-ok{background:rgba(34,197,94,.15);color:var(--ok)}.b-err{background:rgba(239,68,68,.15);color:var(--err)}
.warn{background:rgba(245,158,11,.07);border:1px solid rgba(245,158,11,.2);color:var(--warn);border-radius:8px;padding:13px 16px;font-size:13px;line-height:1.6;margin-bottom:18px}
.btn{display:inline-block;background:var(--accent);color:#fff;padding:11px 24px;border-radius:8px;font-size:15px;font-weight:600;border:none;cursor:pointer;text-decoration:none}
.irow{display:flex;justify-content:space-between;padding:6px 10px;background:var(--bg3);border-radius:5px;font-size:12px;margin-bottom:4px}
