ol{padding-left:18px;font-size:13px;line-height:2.1;color:var(--t2)}ol li strong{color:var(--t1)}
</style></head><body><div class="w">
<h1>&#127921; SpinWheel Pro &nbsp;<span style="color:var(--t2);font-size:15px;font-weight:400">RBAC Patch <?= PATCH_VER ?></span></h1>
<div class="sub">Deploys 22 files implementing the Role-Based Access Control system.</div>
<?php if($RUN): ?>
<?php $allOk=empty($ERRORS)&&!empty($OK); ?>
<div class="card">
<h2><?= $allOk?'<span style="color:var(--ok)">&#10003; Deployment Complete!</span>':'<span style="color:var(--err)">&#10007; Errors Occurred</span>' ?></h2>
<?php foreach($OK as[$rel,$sz]): ?>
<div class="row ok-r"><span>&#10003;</span><span style="flex:1"><?= htmlspecialchars($rel) ?></span><span class="badge b-ok"><?= number_format($sz) ?> B</span></div>
<?php endforeach; ?>
<?php foreach($ERRORS as $e): ?>
<div class="row err-r"><span>&#10007;</span><?= htmlspecialchars($e) ?></div>
<?php endforeach; ?>
</div>
<?php if($allOk): ?>
<div class="card"><h2>Next Steps</h2><ol>
<li><strong>Run the RBAC migration</strong> to create DB tables:<br>
<a href="<?= $URL ?>/admin/migrate_rbac.php?key=swp_rbac_migrate_2025" style="color:#818cf8;font-size:12px"><?= $URL ?>/admin/migrate_rbac.php?key=swp_rbac_migrate_2025</a></li>
<li><strong>Sign in</strong>: <a href="<?= $URL ?>/admin/login.php" style="color:#818cf8"><?= $URL ?>/admin/login.php</a></li>
<li><strong>Create users</strong> via Admin &#8594; Users &#8594; assign roles &amp; org scopes</li>
<li><strong>Delete this file</strong>: <code>rm rbac_patch.php</code></li>
<li><strong>Delete migrate file</strong>: <code>rm admin/migrate_rbac.php</code></li>
</ol></div>
<div class="warn">&#9888; <strong>Security:</strong> Delete <code>rbac_patch.php</code> and <code>admin/migrate_rbac.php</code> from your server immediately after setup.</div>
<?php endif; ?>
<?php else: ?>
<div class="card"><h2>Files to deploy (20)</h2>
<div style="display:grid;grid-template-columns:1fr 1fr;gap:5px;font-size:11px">
<?php foreach(['includes/config.php'=>'RBAC constants & permissions map','includes/Database.php'=>'PDO singleton','includes/auth.php'=>'RBAC auth + orgScopeFilter()','includes/helpers.php'=>'Org tree, pagination, flash msgs','admin/login.php'=>'Login page','admin/logout.php'=>'Logout handler','admin/profile.php'=>'Profile + password change','admin/dashboard.php'=>'Scoped stats + group filter','admin/projects.php'=>'Projects CRUD + group picker','admin/participants.php'=>'Scoped participant list','admin/export.php'=>'CSV/JSON export with scope','admin/organisation.php'=>'Org group tree CRUD','admin/users.php'=>'User management + scope','admin/roles.php'=>'Roles & permissions matrix','admin/header.php'=>'Sidebar w/ RBAC-gated nav','admin/footer.php'=>'Footer','admin/migrate_rbac.php'=>'DB migration (run once, delete)','admin/forgot_password.php'=>'Password reset request','admin/reset_password.php'=>'Password reset form','admin/change_password.php'=>'Change password redirect'] as $f=>$d): ?>
<div style="background:var(--bg3);border:1px solid var(--border);border-radius:5px;padding:7px 9px">
<div style="font-family:monospace;color:#818cf8"><?= htmlspecialchars($f) ?></div>
<div style="color:var(--t2);margin-top:1px"><?= htmlspecialchars($d) ?></div>
