<div class="card"><h2>Pre-flight Check</h2>
<div class="irow"><span class="il">Detected App URL</span><span><?= htmlspecialchars($URL) ?></span></div>
<div class="irow"><span class="il">PHP Version</span><span><?= PHP_VERSION ?></span></div>
<div class="irow"><span class="il">Web root writable</span><span><?= is_writable($ROOT)?'<span style="color:var(--ok)">&#10003; Yes</span>':'<span style="color:var(--err)">&#10007; No — check permissions</span>' ?></span></div>
<div class="irow"><span class="il">includes/ dir</span><span><?= (!is_dir($ROOT.'/includes')||is_writable($ROOT.'/includes'))?'<span style="color:var(--ok)">&#10003; OK</span>':'<span style="color:var(--err)">&#10007; Not writable</span>' ?></span></div>
<div class="irow"><span class="il">admin/ dir</span><span><?= (!is_dir($ROOT.'/admin')||is_writable($ROOT.'/admin'))?'<span style="color:var(--ok)">&#10003; OK</span>':'<span style="color:var(--err)">&#10007; Not writable</span>' ?></span></div>
</div>
<div class="warn">&#9888; This will <strong>overwrite</strong> existing files in <code>includes/</code> and <code>admin/</code>. Back up any customisations first.</div>
<form method="POST"><input type="hidden" name="deploy" value="yes">
<button type="submit" class="btn">&#128640; Deploy RBAC Patch Now</button></form>
<?php endif; ?>
</div></body></html>
